/**
 * Benchmark the Prismatic Refraction wire pipeline:
 *
 *   app.vomit(bytes)
 *     → prism(bytes, k)        (wire-layer lane assignment)
 *     → settleByLane(shards)   (encounter refraction to stable shape)
 *     → storageAssembly(gate)  (reader-side prism-inverse)
 *
 * Reports throughput (bytes/sec, shards/sec) for each stage and for the
 * full `wireToStorage` pipeline across payload sizes and lane counts.
 *
 * Usage:
 *   cd open-source/gnosis
 *   node ./bin/gnode.js run scripts/benchmark-prismatic-refraction.ts
 */

import {
  createRawStream,
  createStorageGate,
  prism,
  settleByLane,
  storageAssembly,
  wireToStorage,
} from '../src/prismatic-refraction';

// ─── Seeded bytes ────────────────────────────────────────────────────

function lcg(seed: number): () => number {
  let s = seed >>> 0;
  return () => {
    s = (Math.imul(s, 1664525) + 1013904223) >>> 0;
    return s;
  };
}

function randomBytes(seed: number, n: number): number[] {
  const rng = lcg(seed);
  const out = new Array<number>(n);
  for (let i = 0; i < n; i++) out[i] = rng() & 0xff;
  return out;
}

// ─── Timer ───────────────────────────────────────────────────────────

function bench<T>(iterations: number, fn: () => T): { meanMs: number; result: T } {
  // Warm-up.
  for (let i = 0; i < Math.min(3, iterations); i++) fn();
  const start = performance.now();
  let result: T = fn();
  for (let i = 1; i < iterations; i++) result = fn();
  const elapsed = performance.now() - start;
  return { meanMs: elapsed / iterations, result };
}

// ─── Formatters ──────────────────────────────────────────────────────

function humanBytes(n: number): string {
  if (n < 1024) return `${n} B`;
  if (n < 1024 * 1024) return `${(n / 1024).toFixed(1)} KB`;
  if (n < 1024 * 1024 * 1024) return `${(n / (1024 * 1024)).toFixed(1)} MB`;
  return `${(n / (1024 * 1024 * 1024)).toFixed(1)} GB`;
}

function humanPerSec(bytes: number, ms: number): string {
  const bytesPerSec = (bytes / ms) * 1000;
  return `${humanBytes(bytesPerSec)}/s`;
}

// ─── Config ──────────────────────────────────────────────────────────

const PAYLOAD_SIZES = [
  1024,       // 1 KB
  8 * 1024,   // 8 KB
  64 * 1024,  // 64 KB
  256 * 1024, // 256 KB
  1024 * 1024, // 1 MB
];

const LANE_COUNTS = [1, 4, 8, 16];

// ─── Run ─────────────────────────────────────────────────────────────

console.log('# Prismatic Refraction — Wire Pipeline Benchmark');
console.log('');
console.log('Formal anchor: `ForkRaceFoldTheorems.PrismaticRefraction` (zero sorry, Init-only).');
console.log('TS SSOT: `open-source/gnosis/src/prismatic-refraction.ts`.');
console.log('');
console.log(`Node ${process.versions.node} on ${process.platform}/${process.arch}.`);
console.log('');

// ─── Stage 1: Prism only ─────────────────────────────────────────────

console.log('## Stage 1 — Prism (content-addressed lane assignment)');
console.log('');
console.log('| Payload | k=1 | k=4 | k=8 | k=16 |');
console.log('|--------|-----|-----|-----|------|');

for (const n of PAYLOAD_SIZES) {
  const stream = createRawStream(randomBytes(1, n));
  const iterations = Math.max(5, Math.floor(1_000_000 / n));
  const cells: string[] = [humanBytes(n)];
  for (const k of LANE_COUNTS) {
    const { meanMs } = bench(iterations, () => prism(stream, k));
    cells.push(humanPerSec(n, meanMs));
  }
  console.log(`| ${cells.join(' | ')} |`);
}

console.log('');

// ─── Stage 2: Settle (encounter refraction to stable shape) ──────────

console.log('## Stage 2 — settleByLane (encounter refraction to stable shape)');
console.log('');
console.log('| Payload | k=1 | k=4 | k=8 | k=16 |');
console.log('|--------|-----|-----|-----|------|');

for (const n of PAYLOAD_SIZES) {
  const stream = createRawStream(randomBytes(2, n));
  const iterations = Math.max(5, Math.floor(500_000 / n));
  const cells: string[] = [humanBytes(n)];
  for (const k of LANE_COUNTS) {
    const shards = prism(stream, k);
    const { meanMs } = bench(iterations, () => settleByLane(shards));
    cells.push(humanPerSec(n, meanMs));
  }
  console.log(`| ${cells.join(' | ')} |`);
}

console.log('');

// ─── Stage 3: Storage assembly (reader-side prism-inverse) ───────────

console.log('## Stage 3 — storageAssembly (reader-side prism-inverse)');
console.log('');
console.log('| Payload | k=1 | k=4 | k=8 | k=16 |');
console.log('|--------|-----|-----|-----|------|');

for (const n of PAYLOAD_SIZES) {
  const stream = createRawStream(randomBytes(3, n));
  const iterations = Math.max(5, Math.floor(2_000_000 / n));
  const cells: string[] = [humanBytes(n)];
  for (const k of LANE_COUNTS) {
    const shards = prism(stream, k);
    const admissible = Array.from({ length: k }, (_, i) => i).filter((i) => i % 2 === 0);
    const gate = createStorageGate(admissible, 1);
    const { meanMs } = bench(iterations, () => storageAssembly(gate, shards));
    cells.push(humanPerSec(n, meanMs));
  }
  console.log(`| ${cells.join(' | ')} |`);
}

console.log('');

// ─── Full wireToStorage pipeline (end-to-end soundness witness) ──────

console.log('## End-to-End — wireToStorage (prism + settle + soundness witness)');
console.log('');
console.log('Matches `THM-WIRE-TO-STORAGE-IS-SOUND` — every call asserts lanes-bounded + payload-preserved.');
console.log('');
console.log('| Payload | k=1 | k=4 | k=8 | k=16 |');
console.log('|--------|-----|-----|-----|------|');

for (const n of PAYLOAD_SIZES) {
  const stream = createRawStream(randomBytes(4, n));
  const iterations = Math.max(5, Math.floor(400_000 / n));
  const cells: string[] = [humanBytes(n)];
  for (const k of LANE_COUNTS) {
    const { meanMs, result } = bench(iterations, () => wireToStorage(stream, k));
    if (!result.lanesBounded || !result.payloadPreserved) {
      console.error(`\nSOUNDNESS FAILURE at n=${n} k=${k}`);
      process.exit(1);
    }
    cells.push(humanPerSec(n, meanMs));
  }
  console.log(`| ${cells.join(' | ')} |`);
}

console.log('');
console.log('All `wireToStorage` invocations passed the soundness witness ');
console.log('(`lanesBounded` and `payloadPreserved` both true for every (payload, k)).');
